extern void my_strcat(char* dest, const char* src1, const char* src2);

#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <cstring>

// Helper to parse comma-separated input
void parse_input(const std::string& input_str, std::string& src1, std::string& src2, size_t& dest_size) {
    std::stringstream ss(input_str);
    std::string segment;
    std::vector<std::string> parts;

    while(std::getline(ss, segment, ',')) {
        parts.push_back(segment);
    }

    src1 = parts[0];
    src2 = parts[1];
    dest_size = std::stoul(parts[2]);
}

int main() {
    std::vector<std::tuple<std::string, std::string, size_t, std::string>> test_data = {
        { "Hello", "World", 50, "HelloWorld" },
        { "Overflow", "Test", 12, "OverflowTest" }, // Combined length 12, buffer size 12. Overflow on null terminator.
        { "", "EmptyFirst", 50, "EmptyFirst" },
        { "EmptySecond", "", 50, "EmptySecond" },
        { "A", "B", 2, "AB" } // Combined length 2, buffer size 2. Overflow on null terminator.
    };

    for (size_t i = 0; i < test_data.size(); ++i) {
        std::string src1_str = std::get<0>(test_data[i]);
        std::string src2_str = std::get<1>(test_data[i]);
        size_t dest_buffer_size = std::get<2>(test_data[i]);
        std::string expected_output = std::get<3>(test_data[i]);

        char* dest_buffer = new char[dest_buffer_size];
        // Initialize buffer to ensure clean state and detect potential issues
        std::memset(dest_buffer, 0, dest_buffer_size);

        // Call the student's function
        my_strcat(dest_buffer, src1_str.c_str(), src2_str.c_str());

        std::cout << "Test Case " << i + 1 << ":\n";
        std::cout << "  Input src1: \"" << src1_str << "\"\n";
        std::cout << "  Input src2: \"" << src2_str << "\"\n";
        std::cout << "  Buffer size: " << dest_buffer_size << "\n";
        std::cout << "  Expected:    \"" << expected_output << "\"\n";

        // For robustness issue, we might see the 'expected' output despite an overflow.
        // The error is in the memory access, not necessarily the visible string content.
        // We'll check if the string content up to expected length matches.
        std::string actual_output_prefix(dest_buffer, std::min(dest_buffer_size, expected_output.length()));
        std::cout << "  Actual (prefix): \"" << actual_output_prefix << "\"\n";

        bool content_match = true;
        if (dest_buffer_size > 0 && expected_output.length() >= dest_buffer_size) {
            // If expected string is longer than buffer, we can only compare up to buffer_size-1 (for null terminator)
            if (std::strncmp(dest_buffer, expected_output.c_str(), dest_buffer_size -1) != 0) {
                content_match = false;
            }
        } else {
            if (std::strcmp(dest_buffer, expected_output.c_str()) != 0) {
                content_match = false;
            }
        }

        if (content_match) {
            std::cout << "  Content Match: PASSED\n";
        } else {
            std::cout << "  Content Match: FAILED\n";
        }
        std::cout << std::endl;

        delete[] dest_buffer;
    }

    return 0;
}
